type Item = { type: string; cursed?: boolean };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
type QuoteResult = { premium: number };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const ITEM_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const CURSE_RATE = 0.5;

const sumBy = <T>(items: T[], f: (x: T) => number): number =>
  items.reduce((acc, x) => acc + f(x), 0);

const baseFor = (item: Item): number => ITEM_BASE_PREMIUMS[item.type];

const surchargeFor = (item: Item): number =>
  item.cursed ? baseFor(item) * CURSE_RATE : 0;

const totalSurchargeFor = (items: Item[]): number => sumBy(items, surchargeFor);

const premiumFor = (totalBase: number, totalSurcharge: number): number =>
  totalBase + totalSurcharge + Math.ceil(totalBase * FIRST_INSURANCE_RATE) + PROCESSING_FEE;

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const group = groups.get(item.type) ?? [];
    group.push(item);
    groups.set(item.type, group);
  }
  return groups;
};

const baseForGroup = (type: string, group: Item[]): number => {
  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
  return sumBy(group, baseFor);
};

const totalBaseFor = (items: Item[]): number =>
  Array.from(groupByType(items)).reduce(
    (total, [type, group]) => total + baseForGroup(type, group),
    0,
  );

const quoteFor = (step: QuoteStep): QuoteResult => ({
  premium: premiumFor(totalBaseFor(step.items), totalSurchargeFor(step.items)),
});

export const processScenario = (input: Scenario): { results: QuoteResult[] } => {
  return { results: input.steps.map(quoteFor) };
};
